import { Config, defineConfig } from "drizzle-kit";

export default defineConfig({
  out: "./src/drizzle/migrations",
  schema: "./src/drizzle/index.ts",
  dialect: "mysql",
  dbCredentials: {
    url: process.env.DATABASE_URL!
  },
  verbose: true,
  strict: true
}) satisfies Config;

export * from "./schemas/user.schema";
export * from "./schemas/post.schema";
export * from "./schemas/category.schema";
export * from "./schemas/comment.schema";
export * from "./schemas/comment-like.schema";
export * from "./schemas/post-like.schema";

import {
  mysqlTable,
  varchar,
  boolean,
  timestamp,
  int,
  json,
  uniqueIndex,
  index,
  mysqlEnum
} from "drizzle-orm/mysql-core";
import { timestamps } from "./schema.helper";
import { relations } from "drizzle-orm";
import { posts } from "./post.schema";
import { postLikes } from "./post-like.schema";
import { commentLikes } from "./comment-like.schema";
import { comments } from "./comment.schema";

interface IAvatar {
  public_id?: string;
  url: string;
  size?: number;
}

export const users = mysqlTable(
  "users",
  {
    id: int("id").primaryKey().autoincrement(),
    name: varchar("name", { length: 100 }).notNull(),
    email: varchar("email", { length: 255 }).notNull().unique(),
    password: varchar("password", { length: 255 }),
    role: mysqlEnum("role", ["user", "admin"]).default("user").notNull(),

    provider: mysqlEnum("provider", ["local", "google", "github"])
      .default("local")
      .notNull(),
    providerId: varchar("provider_id", { length: 255 }),

    avatar: json("avatar").$type<IAvatar>(),

    isEmailVerified: boolean("is_email_verified").default(false).notNull(),
    lastLoginAt: timestamp("last_login_at"),
    failedLoginAttempts: int("failed_login_attempts").default(0).notNull(),
    lockUntil: timestamp("lock_until"),

    isDeleted: boolean("is_deleted").default(false).notNull(),
    deletedAt: timestamp("deleted_at"),
    reActivateAvailableAt: timestamp("re_activate_available_at"),

    ...timestamps
  },
  (table) => [
    uniqueIndex("email_idx").on(table.email),
    index("role_idx").on(table.role),
    index("is_deleted_idx").on(table.isDeleted)
  ]
);

//* relations:
export const usersRelations = relations(users, ({ many }) => ({
  //? relation with posts: user has many posts
  posts: many(posts),

  //? relation with post_likes: user has many likes
  postLikes: many(postLikes),

  //? relation with comment_likes: user has many comment likes
  commentLikes: many(commentLikes),

  //? relation with comments: user has many comments
  comments: many(comments)
}));

//? User type
export type User = typeof users.$inferSelect;
export type NewUser = typeof users.$inferInsert;

import { timestamp } from "drizzle-orm/mysql-core";

export const timestamps = {
  createdAt: timestamp("created_at").defaultNow().notNull(),
  updatedAt: timestamp("updated_at").defaultNow().onUpdateNow().notNull()
};

import {
  index,
  int,
  json,
  mysqlEnum,
  mysqlTable,
  timestamp,
  uniqueIndex,
  varchar
} from "drizzle-orm/mysql-core";
import { timestamps } from "./schema.helper";
import { users } from "./user.schema";
import { relations } from "drizzle-orm";
import { categories } from "./category.schema";
import { postLikes } from "./post-like.schema";

const POST_STATUSES = ["draft", "published", "archived"] as const;

interface IFile {
  public_id: string;
  url: string;
  size: number;
}

export const posts = mysqlTable(
  "posts",
  {
    id: int().primaryKey().autoincrement(),

    title: varchar("title", { length: 100 }).notNull(),
    slug: varchar("slug").notNull().unique(),
    content: varchar("description"),
    excerpt: varchar("excerpt"), // Short summary

    authorId: int("author_id")
      .references(() => users.id, { onDelete: "cascade" })
      .notNull(), // Reference to User
    categoryId: int("category_id")
      .references(() => users.id, { onDelete: "cascade" })
      .notNull(),

    tags: json("tags").$type<string[]>(),
    featuredImage: json("featured_image").$type<IFile>(),
    views: int("views").default(0).notNull(),

    status: mysqlEnum("status", POST_STATUSES).default("draft").notNull(),
    publishedAt: timestamp("published_at"),

    ...timestamps
  },
  (table) => [
    uniqueIndex("author_id_slug_unique").on(table.authorId, table.slug),
    index("category_idx").on(table.categoryId),
    index("status_idx").on(table.status)
  ]
);

//* relations:
export const postsRelations = relations(posts, ({ one, many }) => ({
  //? relation with users: post belongs to one user
  author: one(users, {
    fields: [posts.authorId],
    references: [users.id]
  }),

  //? relation with categories: Post belongs to one category
  category: one(categories, {
    fields: [posts.categoryId],
    references: [categories.id]
  }),

  //? relation with post_likes: one post has many likes
  postLikes: many(postLikes)
}));

export type NewPost = typeof posts.$inferInsert;
export type Post = typeof posts.$inferSelect;

import { mysqlTable, int, uniqueIndex } from "drizzle-orm/mysql-core";
import { users } from "./user.schema";
import { posts } from "./post.schema";
import { timestamps } from "./schema.helper";
import { relations } from "drizzle-orm";

export const postLikes = mysqlTable(
  "post_likes",
  {
    userId: int("user_id")
      .references(() => users.id, { onDelete: "cascade" })
      .notNull(),

    postId: int("post_id")
      .references(() => posts.id, { onDelete: "cascade" })
      .notNull(),
    ...timestamps
  },
  (table) => [uniqueIndex("unique_like").on(table.userId, table.postId)]
);

//* relations:
export const postLikesRelations = relations(postLikes, ({ one }) => ({
  //? relation with users: one like belongs to one user
  user: one(users, {
    fields: [postLikes.userId],
    references: [users.id]
  }),

  //? relation with posts: one like belongs to one post
  post: one(posts, {
    fields: [postLikes.postId],
    references: [posts.id]
  })
}));

import { mysqlTable, int, text } from "drizzle-orm/mysql-core";

import { posts } from "./post.schema";
import { users } from "./user.schema";
import { timestamps } from "./schema.helper";
import { relations } from "drizzle-orm";
import { commentLikes } from "./comment-like.schema";

export const comments = mysqlTable("comments", {
  id: int("id").primaryKey().autoincrement(),

  postId: int("post_id")
    .notNull()
    .references(() => posts.id),

  authorId: int("author_id")
    .notNull()
    .references(() => users.id),

  content: text("content").notNull(),

  parentCommentId: int("parent_comment_id"),
  ...timestamps
});

//* relations:
export const commentsRelations = relations(comments, ({ one, many }) => ({
  //? relation with posts: one comment belongs to one post
  post: one(posts, {
    fields: [comments.postId],
    references: [posts.id]
  }),

  //? relation with users: one comment belongs to one user
  author: one(users, {
    fields: [comments.authorId],
    references: [users.id]
  }),

  //? relation with comments: one comment belongs to one parent comment
  parentComment: one(comments, {
    fields: [comments.parentCommentId],
    references: [comments.id]
  }),

  //? relation with comments: one comment has many replies
  replies: many(comments),

  //? relation with comment_likes: one comment has many likes
  likes: many(commentLikes)
}));

